import { describe, it, expect } from 'vitest';

// Assuming the function is implemented like this for testing purposes:
function proratedRefund(
  planPriceUsd: number,
  periodStart: string,
  cancelDate: string,
): number {
  const start = new Date(periodStart);
  const cancel = new Date(cancelDate);

  if (cancel < start) {
    throw new RangeError('cancelDate cannot be before periodStart');
  }

  const daysElapsed = Math.floor(
    (cancel.getTime() - start.getTime()) / (1000 * 60 * 60 * 24),
  );

  if (daysElapsed > 30) {
    return 0;
  }

  const daysInYear = 365;
  const refund = (planPriceUsd * (daysInYear - daysElapsed)) / daysInYear;

  return Math.round(refund * 100) / 100;
}

describe('proratedRefund', () => {
  it('should calculate prorated refund for cancellation 10 days into period', () => {
    const refund = proratedRefund(365, '2024-01-01', '2024-01-11');
    expect(refund).toBe(355 * (355 / 365));
  });

  it('should return 0 when cancelled exactly 31 days into period', () => {
    const refund = proratedRefund(365, '2024-01-01', '2024-02-01');
    expect(refund).toBe(0);
  });

  it('should throw RangeError when cancelDate is before periodStart', () => {
    expect(() => {
      proratedRefund(365, '2024-01-15', '2024-01-01');
    }).toThrow(RangeError);
  });
});
